import torch
import torch.nn as nn
import math
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel with tiling for better memory access
fused_conv_subtract_mish_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>

template<typename scalar_t>
__device__ __forceinline__ scalar_t mish_activation(scalar_t x) {
    return x * tanhf(log1pf(expf(x)));
}

template<typename scalar_t>
__global__ void fused_conv_subtract_mish_kernel(
    const scalar_t* __restrict__ input,
    const scalar_t* __restrict__ weight,
    const scalar_t* __restrict__ bias,
    scalar_t* __restrict__ output,
    const scalar_t subtract1,
    const scalar_t subtract2,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int height,
    const int width,
    const int kernel_size,
    const int out_height,
    const int out_width,
    const int stride,
    const int padding
) {
    // Use 2D grid for better parallelism
    const int out_h = blockIdx.y * blockDim.y + threadIdx.y;
    const int out_w = blockIdx.x * blockDim.x + threadIdx.x;
    const int c = blockIdx.z;
    const int n = blockIdx.z / out_channels;
    const int oc = blockIdx.z % out_channels;

    if (out_h >= out_height || out_w >= out_width || c >= batch_size * out_channels) return;

    scalar_t result = bias ? bias[oc] : static_cast<scalar_t>(0);

    // Precompute some values
    const int base_h = out_h * stride - padding;
    const int base_w = out_w * stride - padding;

    // Unrolled convolution loop for kernel_size=3
    if (kernel_size == 3) {
        for (int ic = 0; ic < in_channels; ++ic) {
            const scalar_t* input_channel = input + ((n * in_channels + ic) * height * width);
            const scalar_t* weight_channel = weight + ((oc * in_channels + ic) * 9);

            for (int kh = 0; kh < 3; ++kh) {
                const int ih = base_h + kh;
                if (ih >= 0 && ih < height) {
                    for (int kw = 0; kw < 3; kw += 1) {
                        const int iw = base_w + kw;
                        if (iw >= 0 && iw < width) {
                            result += input_channel[ih * width + iw] * weight_channel[kh * 3 + kw];
                        }
                    }
                }
            }
        }
    } else {
        // Generic kernel size
        for (int ic = 0; ic < in_channels; ++ic) {
            const scalar_t* input_channel = input + ((n * in_channels + ic) * height * width);
            const scalar_t* weight_channel = weight + ((oc * in_channels + ic) * kernel_size * kernel_size);

            for (int kh = 0; kh < kernel_size; ++kh) {
                const int ih = base_h + kh;
                if (ih >= 0 && ih < height) {
                    for (int kw = 0; kw < kernel_size; ++kw) {
                        const int iw = base_w + kw;
                        if (iw >= 0 && iw < width) {
                            result += input_channel[ih * width + iw] * weight_channel[kh * kernel_size + kw];
                        }
                    }
                }
            }
        }
    }

    // Apply subtract operations and Mish activation
    result = result - subtract1 - subtract2;
    result = mish_activation(result);

    const int output_idx = ((n * out_channels + oc) * out_height + out_h) * out_width + out_w;
    output[output_idx] = result;
}

torch::Tensor fused_conv_subtract_mish_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float subtract1,
    float subtract2,
    int stride,
    int padding
) {
    // Get tensor dimensions
    const int batch_size = input.size(0);
    const int in_channels = input.size(1);
    const int height = input.size(2);
    const int width = input.size(3);
    const int out_channels = weight.size(0);
    const int kernel_size = weight.size(2);

    // Calculate output dimensions
    const int out_height = (height + 2 * padding - kernel_size) / stride + 1;
    const int out_width = (width + 2 * padding - kernel_size) / stride + 1;

    // Create output tensor
    auto output = torch::empty({batch_size, out_channels, out_height, out_width}, 
                              input.options());

    // Optimized thread block configuration
    const int threads_x = 16;
    const int threads_y = 16;
    dim3 block_size(threads_x, threads_y, 1);

    // Grid configuration - each block handles multiple output positions
    const int grid_x = (out_width + threads_x - 1) / threads_x;
    const int grid_y = (out_height + threads_y - 1) / threads_y;
    const int grid_z = batch_size * out_channels;

    dim3 grid_size(grid_x, grid_y, grid_z);

    // Launch kernel
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_conv_subtract_mish_cuda", ([&] {
        fused_conv_subtract_mish_kernel<scalar_t><<<grid_size, block_size>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            static_cast<scalar_t>(subtract1),
            static_cast<scalar_t>(subtract2),
            batch_size,
            in_channels,
            out_channels,
            height,
            width,
            kernel_size,
            out_height,
            out_width,
            stride,
            padding
        );
    }));

    return output;
}
"""

