fused_conv_subtract_mish = load_inline(
    name="fused_conv_subtract_mish",
    cpp_sources=fused_conv_subtract_mish_cpp_source,
    cuda_sources=fused_conv_subtract_mish_source,
    functions=["fused_conv_subtract_mish_cuda"],
    verbose=False,
    extra_cflags=["-O3", "-use_fast_math"],
    extra_ldflags=[""],
)

class ModelNew(nn.Module):
    """
    Optimized model with fused convolution, subtract, and Mish activation.
    """
    def __init__(self, in_channels, out_channels, kernel_size, subtract_value_1, subtract_value_2):
        super(ModelNew, self).__init__()

        # Store convolution parameters
        self.in_channels = in_channels
        self.out_channels = out_channels
        self.kernel_size = kernel_size
        self.subtract_value_1 = subtract_value_1
        self.subtract_value_2 = subtract_value_2

        # Match nn.Conv2d defaults
        self.stride = 1
        self.padding = 0

        # Initialize convolution weights and bias
        self.weight = nn.Parameter(torch.empty(out_channels, in_channels, kernel_size, kernel_size))
        self.bias = nn.Parameter(torch.empty(out_channels))

        # Initialize parameters
        self.reset_parameters()

        # Store the fused operation
        self.fused_op = fused_conv_subtract_mish

    def reset_parameters(self):
        # Use Kaiming initialization
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        if self.bias is not None:
            fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
            bound = 1 / math.sqrt(fan_in)
            nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        # Apply fused convolution, subtract, and Mish activation
        return self.fused_op.fused_conv_subtract_mish_cuda(
            x, 
            self.weight, 
            self.bias, 
            self.subtract_value_1, 
            self.subtract_value_2,
            self.stride,
            self.padding
        )

