    scalar_t* __restrict__ output,
    const scalar_t subtract1,
    const scalar_t subtract2,
    const int batch_size,
    const int in_channels,
    const int out_channels,
    const int height,
    const int width,
    const int kernel_size,
    const int out_height,
    const int out_width,
    const int stride,
    const int padding
) {
    // Use 2D grid for better parallelism
    const int out_h = blockIdx.y * blockDim.y + threadIdx.y;
    const int out_w = blockIdx.x * blockDim.x + threadIdx.x;
    const int c = blockIdx.z;
    const int n = blockIdx.z / out_channels;
    const int oc = blockIdx.z % out_channels;

    if (out_h >= out_height || out_w >= out_width || c >= batch_size * out_channels) return;

    scalar_t result = bias ? bias[oc] : static_cast<scalar_t>(0);

    // Precompute some values
    const int base_h = out_h * stride - padding;
    const int base_w = out_w * stride - padding;

    // Unrolled convolution loop for kernel_size=3
    if (kernel_size == 3) {
        for (int ic = 0; ic < in_channels; ++ic) {
            const scalar_t* input_channel = input + ((n * in_channels + ic) * height * width);
            const scalar_t* weight_channel = weight + ((oc * in_channels + ic) * 9);

            for (int kh = 0; kh < 3; ++kh) {
                const int ih = base_h + kh;
                if (ih >= 0 && ih < height) {
                    for (int kw = 0; kw < 3; kw += 1) {
                        const int iw = base_w + kw;
                        if (iw >= 0 && iw < width) {
                            result += input_channel[ih * width + iw] * weight_channel[kh * 3 + kw];
                        }
                    }
                }
            }
        }
    } else {
        // Generic kernel size
        for (int ic = 0; ic < in_channels; ++ic) {
            const scalar_t* input_channel = input + ((n * in_channels + ic) * height * width);
            const scalar_t* weight_channel = weight + ((oc * in_channels + ic) * kernel_size * kernel_size);

            for (int kh = 0; kh < kernel_size; ++kh) {
                const int ih = base_h + kh;
                if (ih >= 0 && ih < height) {
                    for (int kw = 0; kw < kernel_size; ++kw) {
                        const int iw = base_w + kw;
                        if (iw >= 0 && iw < width) {
                            result += input_channel[ih * width + iw] * weight_channel[kh * kernel_size + kw];
                        }
                    }
                }
            }
        }
    }

    // Apply subtract operations and Mish activation
    result = result - subtract1 - subtract2;
    result = mish_activation(result);

    const int output_idx = ((n * out_channels + oc) * out_height + out_h) * out_width + out_w;
    output[output_idx] = result;
}

